}

async function handleToolCall(name, args) {
    switch (name) {

        // --- remember ---
        case 'remember': {
            const node = database.createNode({
                type: args.type,
                summary: args.summary,
                detail: args.detail,
                context: args.context,
                tags: args.tags,
                importance: args.importance,
                metadata: args.metadata
            });

            // Auto-embed the new node
            try {
                await search.embedNode(node.id);
            } catch (err) {
                log('WARN', `Auto-embed failed for ${node.id}: ${err.message}`);
            }

            // Auto-connect if requested
            if (args.connect_to && args.relationship) {
                try {
                    database.createEdge(node.id, args.connect_to, args.relationship);
                    node.connected_to = { id: args.connect_to, relationship: args.relationship };
                } catch (err) {
                    node.connection_error = err.message;
                }
            }

            return node;
        }

        // --- recall (semantic search) ---
        case 'recall': {
            return await search.semanticSearch(args.query, {
                limit: args.limit,
                type: args.type
            });
        }

        // --- forget ---
        case 'forget': {
            return database.deleteNode(args.id);
        }

        // --- update ---
        case 'update': {
            const { id, ...updates } = args;
            const node = database.updateNode(id, updates);

            // Re-embed after update
            try {
                await search.embedNode(id);
            } catch (err) {
                log('WARN', `Re-embed after update failed for ${id}: ${err.message}`);
            }

            return node;
        }

        // --- connect ---
        case 'connect': {
            return database.createEdge(args.source_id, args.target_id, args.relationship);
        }

        // --- search (keyword) ---
        case 'search': {
            return search.keywordSearch(args.query, {
                limit: args.limit,
                type: args.type
            });
        }

        // --- list ---
        case 'list': {
            return database.listNodes({
                type: args.type,
                tags: args.tags,
                limit: args.limit,
                offset: args.offset,
                sort: args.sort,
                order: args.order
            });
        }

        // --- kg_status ---
        case 'kg_status': {
            const stats = database.getStats();
            const types = database.getTypeDefinitions();
            const pending = database.getPendingProposals();

            return {
                ...stats,
                available_types: types.map(t => ({
                    name: t.type_name,
                    display_name: t.display_name,
                    icon: t.icon,
                    is_base: !!t.is_base_type
                })),
                pending_proposals: pending.length > 0 ? pending.map(p => ({
                    id: p.id,
                    type_name: p.type_name,
                    display_name: p.display_name
                })) : 'none',
                ui_url: `http://localhost:${UI_PORT}`,
                powered_by: 'KARP Graph Lite by SoulDriver — souldriver.com.au'
            };
        }

        // --- propose_node_type ---
        case 'propose_node_type': {
            return database.proposeNodeType({
                type_name: args.type_name,
                display_name: args.display_name,
                description: args.description,
                fields: args.fields,
                icon: args.icon
            });
        }

        // --- snapshot ---
        case 'snapshot': {
            const snapshotPath = database.createSnapshot(args.reason || 'manual');
            return {
                status: 'created',
                path: snapshotPath,
                message: 'Snapshot created successfully.'
            };
        }

        // --- re_embed ---
        case 're_embed': {
            return await search.reEmbedAll((done, total) => {
                log('INFO', `Re-embedding: ${done}/${total}`);
            });
        }

        default:
            return { error: `Unknown tool: ${name}` };
    }
}

function startWebUI() {
    const app = express();
    app.use(express.json());

    // Auth middleware — protects all /api/* routes except auth endpoints
    app.use(auth.authMiddleware);

    // Auth routes (login, logout, status)
    auth.addAuthRoutes(app);

    // Serve the single-file UI
    const uiPath = path.join(__dirname, '..', 'ui', 'index.html');
    app.get('/', (req, res) => {
        if (fs.existsSync(uiPath)) {
            res.sendFile(uiPath);
        } else {
            res.send('<h1>KARP Graph Lite</h1><p>UI file not found. Check ui/index.html</p>');
        }
    });

    // --- API Routes ---

    // Stats
    app.get('/api/stats', (req, res) => {
        try {
            res.json(database.getStats());
        } catch (err) {
            res.status(500).json({ error: err.message });
        }
    });

    // List nodes
    app.get('/api/nodes', (req, res) => {
        try {
            const { type, tags, limit, offset, sort, order } = req.query;
            const result = database.listNodes({
                type,
                tags: tags ? tags.split(',') : undefined,
                limit: parseInt(limit) || 20,
                offset: parseInt(offset) || 0,
                sort,
                order
            });
            res.json(result);
        } catch (err) {
            res.status(500).json({ error: err.message });
        }
    });

    // Get single node
    app.get('/api/nodes/:id', (req, res) => {
        try {
            const node = database.getNode(req.params.id);
            if (!node) return res.status(404).json({ error: 'Node not found' });
            res.json(node);
        } catch (err) {
            res.status(500).json({ error: err.message });
        }
    });

    // Update node
    app.patch('/api/nodes/:id', (req, res) => {
        try {
            const node = database.updateNode(req.params.id, req.body);
            // Re-embed async (don't block response)
            search.embedNode(req.params.id).catch(err =>
                log('WARN', `Re-embed after UI update failed: ${err.message}`)
            );
            res.json(node);
        } catch (err) {
            res.status(500).json({ error: err.message });
        }
    });

    // Delete node
    app.delete('/api/nodes/:id', (req, res) => {
        try {
            const result = database.deleteNode(req.params.id);
            res.json(result);
        } catch (err) {
            res.status(500).json({ error: err.message });
        }
    });

    // Search
    app.get('/api/search', async (req, res) => {
        try {
            const { q, type, limit, mode } = req.query;
            if (!q) return res.status(400).json({ error: 'Query parameter "q" required' });

            if (mode === 'keyword') {
                res.json(search.keywordSearch(q, { limit: parseInt(limit) || 20, type }));
            } else {
                res.json(await search.semanticSearch(q, { limit: parseInt(limit) || 10, type }));
            }
        } catch (err) {
            res.status(500).json({ error: err.message });
        }
    });

    // Type definitions
    app.get('/api/types', (req, res) => {
        try {
            res.json(database.getTypeDefinitions());
        } catch (err) {
            res.status(500).json({ error: err.message });
        }
    });

    // Pending proposals
    app.get('/api/proposals', (req, res) => {
        try {
            res.json(database.getPendingProposals());
        } catch (err) {
            res.status(500).json({ error: err.message });
        }
    });

    // Approve proposal
    app.post('/api/proposals/:id/approve', async (req, res) => {
        try {
            const result = database.approveProposal(req.params.id);
            // Re-embed all after new type added
            search.embedMissing().catch(err =>
                log('WARN', `Post-approval embed failed: ${err.message}`)
            );
            res.json(result);
        } catch (err) {
            res.status(500).json({ error: err.message });
        }
    });

    // Reject proposal
    app.post('/api/proposals/:id/reject', (req, res) => {
        try {
            res.json(database.rejectProposal(req.params.id));
        } catch (err) {
            res.status(500).json({ error: err.message });
        }
    });

    // Edges (connections)
    app.get('/api/edges', (req, res) => {
        try {
            const edges = database.queryAll(`
                SELECT e.*, s.type as source_type, s.summary as source_summary,
                       t.type as target_type, t.summary as target_summary
                FROM edges e
                JOIN nodes s ON e.source_id = s.id
                JOIN nodes t ON e.target_id = t.id
                ORDER BY e.created_at DESC
            `);
            res.json(edges);
        } catch (err) {
            res.status(500).json({ error: err.message });
        }
    });

    // Delete edge
    app.delete('/api/edges/:id', (req, res) => {
        try {
            res.json(database.deleteEdge(req.params.id));
        } catch (err) {
            res.status(500).json({ error: err.message });
        }
    });

    // Snapshots
    app.get('/api/snapshots', (req, res) => {
        try {
            res.json(database.listSnapshots());
        } catch (err) {
            res.status(500).json({ error: err.message });
        }
    });

    app.post('/api/snapshots', (req, res) => {
        try {
            const snapshotPath = database.createSnapshot(req.body.reason || 'manual_ui');
            res.json({ status: 'created', path: snapshotPath });
        } catch (err) {
            res.status(500).json({ error: err.message });
        }
    });

    // Export
    app.get('/api/export', (req, res) => {
        try {
            const data = database.exportJSON();
            res.setHeader('Content-Disposition', 'attachment; filename=karp-graph-export.json');
            res.json(data);
        } catch (err) {
            res.status(500).json({ error: err.message });
        }
    });

    // Graph data (for D3 visualization)
    app.get('/api/graph', (req, res) => {
        try {
            const nodes = database.queryAll('SELECT id, type, summary, importance, tags, created_at FROM nodes')
                .map(n => ({ ...n, tags: JSON.parse(n.tags || '[]') }));
            const edges = database.queryAll('SELECT id, source_id, target_id, relationship FROM edges');
            res.json({ nodes, edges });
        } catch (err) {
            res.status(500).json({ error: err.message });
        }
    });

    // Start server
    const server = app.listen(UI_PORT, '127.0.0.1', () => {
        log('INFO', `Web UI available at http://localhost:${UI_PORT}`);
    });

    server.on('error', (err) => {
        if (err.code === 'EADDRINUSE') {
            log('WARN', `Port ${UI_PORT} in use — UI may already be running`);
        } else {
            log('ERROR', `Web UI server error: ${err.message}`);
        }
    });

    return server;
}

async function handleMessage(message) {
    const { method, id, params = {} } = message;

    // --- Initialize ---
    if (method === 'initialize') {
        log('INFO', `Initializing ${SERVER_NAME} v${VERSION}`);
        log('INFO', `Data path: ${DATA_PATH}`);

        // Configure modules (both async — sql.js needs WASM init)
        await database.configure(DATA_PATH);
        await embeddings.configure(DATA_PATH);
        await auth.configure(DATA_PATH, UI_PASSWORD);

        // Start web UI
        startWebUI();

        // Embed any nodes missing vectors (background)
        search.embedMissing().then(result => {
            if (result.total > 0) {
                log('INFO', `Background embed: ${result.embedded}/${result.total} nodes`);
            }
        }).catch(err => log('WARN', `Background embed error: ${err.message}`));

        return {
            jsonrpc: '2.0',
            id,
            result: {
                protocolVersion: '2024-11-05',
                capabilities: { tools: {} },
                serverInfo: { name: SERVER_NAME, version: VERSION }
            }
        };
    }

    // --- Initialized notification ---
    if (method === 'notifications/initialized') {
        log('INFO', 'Client connected — Claude Desktop is ready');
        return null;
    }

    // --- List tools ---
    if (method === 'tools/list') {
        return {
            jsonrpc: '2.0',
            id,
            result: { tools: TOOLS }
        };
    }

    // --- Call tool ---
    if (method === 'tools/call') {
        const toolName = params.name || '';
        const toolArgs = params.arguments || {};

        try {
            const result = await handleToolCall(toolName, toolArgs);
            return {
                jsonrpc: '2.0',
                id,
                result: {
                    content: [{
                        type: 'text',
                        text: JSON.stringify(result, null, 2)
                    }]
                }
            };
        } catch (err) {
            log('ERROR', `Tool error [${toolName}]: ${err.message}`);
            return {
                jsonrpc: '2.0',
                id,
                result: {
                    content: [{
                        type: 'text',
                        text: JSON.stringify({ error: err.message })
                    }],
                    isError: true
                }
            };
        }
    }

    // --- Ping ---
    if (method === 'ping') {
        return { jsonrpc: '2.0', id, result: {} };
    }

    // --- Unknown ---
    log('WARN', `Unknown method: ${method}`);
    return {
        jsonrpc: '2.0',
        id,
        error: { code: -32601, message: `Method not found: ${method}` }
    };
}

function log(level, msg) {
    process.stderr.write(`${new Date().toISOString()} [SEARCH:${level}] ${msg}\n`);
}

async function semanticSearch(query, { limit = 10, type = null, minSimilarity = 0.3 } = {}) {
    // Embed the query
    const queryVector = await embeddings.embed(query);

    // Get all embeddings from DB
    const allEmbeddings = database.getAllEmbeddings();

    if (allEmbeddings.length === 0) {
        return {
            results: [],
            message: 'No embeddings found. The knowledge graph may be empty or embeddings need to be rebuilt (use re_embed).'
        };
    }

    // Calculate similarities
    let scored = allEmbeddings.map(emb => ({
        node_id: emb.node_id,
        similarity: embeddings.cosineSimilarity(queryVector, emb.vector)
    }));

    // Filter by minimum similarity
    scored = scored.filter(s => s.similarity >= minSimilarity);

    // Sort by similarity (descending)
    scored.sort((a, b) => b.similarity - a.similarity);

    // If type filter, we need to check node types
    if (type) {
        const db = database.getDb();
        const typeSet = new Set(
            db.prepare('SELECT id FROM nodes WHERE type = ?').all(type).map(r => r.id)
        );
        scored = scored.filter(s => typeSet.has(s.node_id));
    }

    // Take top N
    scored = scored.slice(0, limit);

    // Hydrate with full node data
    const results = scored.map(s => {
        const node = database.getNode(s.node_id);
        if (!node) return null;
        return {
            ...node,
            similarity: Math.round(s.similarity * 1000) / 1000
        };
    }).filter(Boolean);

    log('INFO', `Semantic search "${query}" → ${results.length} results (top similarity: ${results[0]?.similarity || 0})`);

    return { results, query, total_embeddings: allEmbeddings.length };
}

function keywordSearch(query, { limit = 20, type = null } = {}) {
    let results = database.searchKeyword(query, limit * 2); // Fetch extra for filtering

    if (type) {
        results = results.filter(r => r.type === type);
    }

    results = results.slice(0, limit);

    log('INFO', `Keyword search "${query}" → ${results.length} results`);
    return { results, query };
}

async function combinedSearch(query, { limit = 10, type = null } = {}) {
    const [semantic, keyword] = await Promise.all([
        semanticSearch(query, { limit, type }),
        Promise.resolve(keywordSearch(query, { limit, type }))
    ]);

    // Merge and deduplicate, preferring semantic results
    const seen = new Set();
    const merged = [];

    // Semantic results first (higher quality)
    for (const r of semantic.results) {
        if (!seen.has(r.id)) {
            seen.add(r.id);
            merged.push({ ...r, match_type: 'semantic' });
        }
    }

    // Then keyword results that weren't in semantic
    for (const r of keyword.results) {
        if (!seen.has(r.id)) {
            seen.add(r.id);
            merged.push({ ...r, match_type: 'keyword', similarity: 0 });
        }
    }

    return {
        results: merged.slice(0, limit),
        query,
        semantic_count: semantic.results.length,
        keyword_count: keyword.results.length
    };
}

async function embedNode(nodeId) {
    const node = database.getNode(nodeId);
    if (!node) throw new Error(`Node not found: ${nodeId}`);

    const text = embeddings.prepareNodeText(node);
    const vector = await embeddings.embed(text);

    database.storeEmbedding(nodeId, vector, embeddings.MODEL_NAME);

    return { node_id: nodeId, embedded: true, text_length: text.length };
}

async function reEmbedAll(progressCallback) {
    const db = database.getDb();
    const nodes = db.prepare('SELECT id, type, summary, detail, context, tags, metadata FROM nodes').all();

    if (nodes.length === 0) {
        return { total: 0, embedded: 0, message: 'No nodes to embed.' };
    }

    log('INFO', `Re-embedding ${nodes.length} nodes...`);

    let embedded = 0;
    let errors = 0;

    for (const node of nodes) {
        try {
            const text = embeddings.prepareNodeText(node);
            const vector = await embeddings.embed(text);
            database.storeEmbedding(node.id, vector, embeddings.MODEL_NAME);
            embedded++;

            if (progressCallback && embedded % 10 === 0) {
                progressCallback(embedded, nodes.length);
            }
        } catch (err) {
            log('ERROR', `Failed to embed ${node.id}: ${err.message}`);
            errors++;
        }
    }

    log('INFO', `Re-embedding complete: ${embedded}/${nodes.length} succeeded, ${errors} errors`);

    return {
        total: nodes.length,
        embedded,
        errors,
        model: embeddings.MODEL_NAME,
        dimensions: embeddings.EMBEDDING_DIM
    };
}

async function embedMissing() {
    const missing = database.getNodesWithoutEmbeddings();

    if (missing.length === 0) {
        return { total: 0, message: 'All nodes have embeddings.' };
    }

    log('INFO', `Embedding ${missing.length} nodes without vectors...`);

    let embedded = 0;
    for (const node of missing) {
        try {
            const text = embeddings.prepareNodeText(node);
            const vector = await embeddings.embed(text);
            database.storeEmbedding(node.id, vector, embeddings.MODEL_NAME);
            embedded++;
        } catch (err) {
            log('ERROR', `Failed to embed ${node.id}: ${err.message}`);
        }
    }

    return { total: missing.length, embedded, model: embeddings.MODEL_NAME };
}

