async function doSearch(mode) {
    const input = document.getElementById('search-input');
    state.searchQuery = input ? input.value.trim() : '';
    if (!state.searchQuery) { await loadBrowseResults(); return; }

    const resultsEl = document.getElementById('browse-results');
    if (!resultsEl) return;
    resultsEl.innerHTML = '<div class="loading"><div class="spinner"></div>Searching...</div>';

    try {
        let url = `/api/search?q=${encodeURIComponent(state.searchQuery)}&limit=20`;
        if (mode === 'keyword') url += '&mode=keyword';
        if (state.filterType) url += `&type=${state.filterType}`;

        const data = await api(url);
        const results = data.results || data;
        resultsEl.innerHTML = results.length > 0
            ? results.map(n => renderNodeCard(n)).join('')
            : '<div class="empty-state"><div class="icon">🔍</div><h3>No results</h3><p>Try different search terms</p></div>';
    } catch {}
}

