async function renderGraph(el) {
    el.innerHTML = `
        <div class="page-header">
            <h2>Graph View</h2>

const g = svg.append('g');

    // Zoom
    const zoom = d3.zoom().scaleExtent([0.1, 4]).on('zoom', (event) => {
        g.attr('transform', event.transform);
    });
    svg.call(zoom);
    window._graphZoom = zoom;
    window._graphSvg = svg;

    // Simulation
    const simulation = d3.forceSimulation(data.nodes)
        .force('link', d3.forceLink(links).id(d => d.id).distance(120))
        .force('charge', d3.forceManyBody().strength(-200))
        .force('center', d3.forceCenter(width / 2, height / 2))
        .force('collision', d3.forceCollide().radius(30));

    // Links
    const link = g.append('g').selectAll('line')
        .data(links).join('line')
        .attr('class', 'graph-link')
        .attr('stroke-width', 1.5);

    // Link labels
    const linkLabel = g.append('g').selectAll('text')
        .data(links).join('text')
        .attr('class', 'graph-link-label')
        .text(d => d.relationship);

    // Nodes
    const node = g.append('g').selectAll('g')
        .data(data.nodes).join('g')
        .attr('class', 'graph-node')
        .call(d3.drag()
            .on('start', (event, d) => { if (!event.active) simulation.alphaTarget(0.3).restart(); d.fx = d.x; d.fy = d.y; })
            .on('drag', (event, d) => { d.fx = event.x; d.fy = event.y; })
            .on('end', (event, d) => { if (!event.active) simulation.alphaTarget(0); d.fx = null; d.fy = null; })
        )
        .on('click', (event, d) => openNodeModal(d.id));

    node.append('circle')

.attr('r', d => 6 + (d.importance || 0.5) * 10)
        .attr('fill', d => getColor(d.type))
        .attr('fill-opacity', 0.8)
        .attr('stroke', d => getColor(d.type))
        .attr('stroke-opacity', 0.3)
        .attr('stroke-width', 4);

    node.append('text')
        .attr('dx', 14).attr('dy', 4)
        .text(d => d.summary.length > 30 ? d.summary.slice(0, 30) + '...' : d.summary);

    // Tick
    simulation.on('tick', () => {
        link.attr('x1', d => d.source.x).attr('y1', d => d.source.y)
            .attr('x2', d => d.target.x).attr('y2', d => d.target.y);
        linkLabel.attr('x', d => (d.source.x + d.target.x) / 2)
            .attr('y', d => (d.source.y + d.target.y) / 2);
        node.attr('transform', d => `translate(${d.x},${d.y})`);
    });
}

function resetGraphZoom() {
    if (window._graphSvg && window._graphZoom) {
        window._graphSvg.transition().duration(500).call(window._graphZoom.transform, d3.zoomIdentity);
    }
}

