        </div>

        <div class="card">
            <h3 style="margin-bottom:12px;">Database</h3>
            <p style="font-size:13px; color:var(--text-secondary); margin-bottom:4px;">
                <strong>Path:</strong> <code style="color:var(--teal);">${state.stats.db_path || 'unknown'}</code>
            </p>
            <p style="font-size:13px; color:var(--text-secondary);">
                <strong>Size:</strong> ${state.stats.db_size} &nbsp;|&nbsp;
                <strong>Nodes:</strong> ${state.stats.total_nodes} &nbsp;|&nbsp;

`;
        } else {
            el.textContent = 'Trust mode is active — web UI is open on localhost without a password.';
            el.style.color = 'var(--amber)';
            if (actionsEl) actionsEl.innerHTML = `
                <button class="btn btn-sm" onclick="showChangePassword()">Set a Passphrase</button>
            `;
        }
    } catch {
        el.textContent = 'Could not check auth status.';
    }
}

function showChangePassword() {
    const form = document.getElementById('change-pw-form');
    form.style.display = 'block';
    document.getElementById('settings-current-pw').value = '';
    document.getElementById('settings-new-pw').value = '';
    document.getElementById('settings-confirm-pw').value = '';
    document.getElementById('change-pw-error').style.display = 'none';
    document.getElementById('settings-new-pw').focus();
}

async function doChangePassword() {
    const current = document.getElementById('settings-current-pw').value;
    const newPw = document.getElementById('settings-new-pw').value;
    const confirm = document.getElementById('settings-confirm-pw').value;
    const errorEl = document.getElementById('change-pw-error');

    if (!newPw || newPw.length < 4) {
        errorEl.textContent = 'New passphrase must be at least 4 characters.';
        errorEl.style.display = 'block';
        return;
    }
    if (newPw !== confirm) {
        errorEl.textContent = 'Passphrases do not match.';
        errorEl.style.display = 'block';

return;
    }

    try {
        const res = await fetch('/api/auth/change-password', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ current_password: current, new_password: newPw })
        });
        const data = await res.json();

        if (data.success) {
            document.getElementById('change-pw-form').style.display = 'none';
            toast('Passphrase updated');
            updateAuthStatus();
        } else {
            errorEl.textContent = data.error || 'Failed to change passphrase';
            errorEl.style.display = 'block';
        }
    } catch {
        errorEl.textContent = 'Connection error';
        errorEl.style.display = 'block';
    }
}

async function doLogout() {
    try {
        await fetch('/api/auth/logout', { method: 'POST' });
        window.location.reload();
    } catch {}
}

async function createSnapshotUI() {
    try {
        await api('/api/snapshots', { method: 'POST', body: { reason: 'manual_ui' } });
        toast('Snapshot created');
        renderPage();
    } catch {}
}

function exportGraph() {
    window.open('/api/export', '_blank');
}

// ---------------------------------------------------------------------------
// Node Card Component
// ---------------------------------------------------------------------------

function renderNodeCard(node) {
    const tags = (node.tags || []).map(t => `<span class="tag">${t}</span>`).join('');
    const date = new Date((node.updated_at || node.created_at) * 1000).toLocaleDateString();

const similarity = node.similarity ? ` • ${Math.round(node.similarity * 100)}% match` : '';

    return `
        <div class="node-card" onclick="openNodeModal('${node.id}')">
            <div class="node-header">
                <span class="node-type">${node.type}</span>
                <span style="font-size:11px; color:var(--text-muted);">${date}${similarity}</span>
            </div>
            <div class="node-summary">${escapeHTML(node.summary)}</div>
            ${node.detail ? `<div class="node-detail">${escapeHTML(node.detail)}</div>` : ''}
            <div class="node-tags">${tags}</div>
        </div>
    `;
}

// ---------------------------------------------------------------------------
// Node Detail Modal
// ---------------------------------------------------------------------------

async function openNodeModal(id) {
    const modal = document.getElementById('node-modal');
    const content = document.getElementById('node-modal-content');

    content.innerHTML = '<div class="loading"><div class="spinner"></div>Loading...</div>';
    modal.classList.add('active');

    try {
        const node = await api(`/api/nodes/${id}`);

        const connections = node.connections || { outgoing: [], incoming: [] };
        const connectionsHTML = [...connections.outgoing, ...connections.incoming].length > 0
            ? `<div style="margin-top:12px;">
                <label>Connections</label>
                ${connections.outgoing.map(c => `<div style="font-size:13px; color:var(--text-secondary); padding:4px 0;">→ <strong>${c.relationship}</strong> → ${escapeHTML(c.summary)} <span class="node-type">${c.type}</span></div>`).join('')}

${connections.incoming.map(c => `<div style="font-size:13px; color:var(--text-secondary); padding:4px 0;">← <strong>${c.relationship}</strong> ← ${escapeHTML(c.summary)} <span class="node-type">${c.type || c.source_type}</span></div>`).join('')}
               </div>`
            : '';

        const metaEntries = Object.entries(node.metadata || {}).filter(([k, v]) => v);
        const metaHTML = metaEntries.length > 0
            ? `<div style="margin-top:12px;"><label>Metadata</label>
                ${metaEntries.map(([k, v]) => `<div style="font-size:13px; color:var(--text-secondary); padding:2px 0;"><strong>${k}:</strong> ${Array.isArray(v) ? v.join(', ') : escapeHTML(String(v))}</div>`).join('')}
               </div>`
            : '';

        content.innerHTML = `
            <div style="display:flex; justify-content:space-between; align-items:flex-start; margin-bottom:16px;">
                <div>
                    <span class="node-type" style="margin-bottom:6px;">${node.type}</span>
                    <h3 style="margin-top:8px;">${escapeHTML(node.summary)}</h3>
                </div>
                <button class="btn btn-sm" onclick="closeModal()" style="flex-shrink:0;">✕</button>
            </div>

            ${node.context ? `<div style="font-size:12px; color:var(--text-muted); margin-bottom:8px;">Context: ${escapeHTML(node.context)}</div>` : ''}

            ${node.detail ? `<div style="font-size:14px; color:var(--text-secondary); white-space:pre-wrap; margin-bottom:12px; padding:12px; background:var(--bg-tertiary); border-radius:var(--radius); max-height:300px; overflow-y:auto;">${escapeHTML(node.detail)}</div>` : ''}

});

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function navigateTo(page) {
    state.page = page;
    document.querySelectorAll('.nav-item').forEach(n => {
        n.classList.toggle('active', n.dataset.page === page);
    });
    renderPage();
}

function escapeHTML(str) {
    if (!str) return '';
    return str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

function formatBytes(bytes) {
    if (bytes > 1024 * 1024) return `${(bytes / 1024 / 1024).toFixed(1)} MB`;
    if (bytes > 1024) return `${(bytes / 1024).toFixed(0)} KB`;
    return `${bytes} B`;
}

function toast(message, type = 'success') {
    const el = document.createElement('div');
    el.className = `toast ${type}`;
    el.textContent = message;
    document.body.appendChild(el);
    setTimeout(() => el.remove(), 3000);
}

// ---------------------------------------------------------------------------
// Auth
// ---------------------------------------------------------------------------

async function checkAuth() {
    try {
        const res = await fetch('/api/auth/status');
        const data = await res.json();

        // First-run setup needed
        if (data.needs_setup) {
            document.getElementById('setup-overlay').classList.add('active');
            document.getElementById('setup-password').focus();
            return false;

}

        // Auth enabled but not logged in
        if (data.auth_enabled && !data.authenticated) {
            document.getElementById('login-overlay').classList.add('active');
            document.getElementById('login-password').focus();
            return false;
        }
        return true;
    } catch {
        return true; // If auth check fails, proceed (server may not have auth)
    }
}

async function doSetupPassword() {
    const password = document.getElementById('setup-password').value;
    const confirm = document.getElementById('setup-confirm').value;
    const errorEl = document.getElementById('setup-error');

    if (!password || password.length < 4) {
        errorEl.textContent = 'Passphrase must be at least 4 characters.';
        errorEl.style.display = 'block';
        return;
    }
    if (password !== confirm) {
        errorEl.textContent = 'Passphrases do not match.';
        errorEl.style.display = 'block';
        document.getElementById('setup-confirm').value = '';
        document.getElementById('setup-confirm').focus();
        return;
    }

    try {
        const res = await fetch('/api/auth/setup', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ password })
        });
        const data = await res.json();

        if (data.success) {
            document.getElementById('setup-overlay').classList.remove('active');
            errorEl.style.display = 'none';

toast('Passphrase set — your knowledge graph is protected');
            renderPage();
        } else {
            errorEl.textContent = data.error || 'Setup failed';
            errorEl.style.display = 'block';
        }
    } catch {
        errorEl.textContent = 'Connection error';
        errorEl.style.display = 'block';
    }
}

async function doSetupTrust() {
    try {
        const res = await fetch('/api/auth/trust', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' }
        });
        const data = await res.json();

        if (data.success) {
            document.getElementById('setup-overlay').classList.remove('active');
            toast('Trust mode enabled — no password required');
            renderPage();
        }
    } catch {
        const errorEl = document.getElementById('setup-error');
        errorEl.textContent = 'Connection error';
        errorEl.style.display = 'block';
    }
}

async function doLogin() {
    const password = document.getElementById('login-password').value;
    const remember = document.getElementById('login-remember').checked;
    const errorEl = document.getElementById('login-error');

    if (!password) return;

    try {
        const res = await fetch('/api/auth/login', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ password, remember })
        });
        const data = await res.json();

        if (data.success) {

document.getElementById('login-overlay').classList.remove('active');
            errorEl.style.display = 'none';
            renderPage();
        } else {
            errorEl.style.display = 'block';
            document.getElementById('login-password').value = '';
            document.getElementById('login-password').focus();
        }
    } catch {
        errorEl.textContent = 'Connection error';
        errorEl.style.display = 'block';
    }
}

// ---------------------------------------------------------------------------
// Boot
// ---------------------------------------------------------------------------

(async () => {
    const authed = await checkAuth();
    if (authed) renderPage();
})();

</script>
</body>
</html>
